build a game following these specs below using phaser 3
{
  "project": "Power Grid Hashi Puzzle Game",
  "description": "A web-based Hashiwokakero (bridges) puzzle game where players connect houses with power cables. Built with Phaser 3 game framework.",

  "game_mechanics": {
    "objective": "Connect all houses with power cables to light them up",
    "rules": [
      "Each house shows how many cables it needs (1-8)",
      "Houses can only connect horizontally or vertically",
      "Cables cannot cross each other",
      "Cables cannot pass through other houses",
      "Click same connection 1-3 times: add cable 1, add cable 2, remove connection",
      "All houses must be connected in one network"
    ],
    "win_condition": "All houses have correct number of connections AND all connected in one network"
  },

  "ui_features": {
    "startup": "Show rules/instructions popup, then difficulty selection (Easy/Medium/Hard)",
    "hud": {
      "top_left": "Stats showing completed puzzles and time per difficulty",
      "top_center": "Current puzzle timer",
      "top_right": "RULES, RESTART, NEXT buttons",
      "bottom_right": "Red flag button to report unsolvable puzzles"
    },
    "victory": "Popup overlay with completion message, time, and NEXT button"
  },

  "difficulty_levels": {
    "easy": {
      "grid": "5x5 usable grid",
      "nodes": "6-9 houses",
      "max_connections": 4,
      "house_scale": 1.0
    },
    "medium": {
      "grid": "7x7 usable grid", 
      "nodes": "8-12 houses",
      "max_connections": 6,
      "house_scale": 0.85
    },
    "hard": {
      "grid": "10x10 usable grid",
      "nodes": "12-18 houses", 
      "max_connections": 8,
      "house_scale": 0.7
    }
  },

  "visual_design": {
    "background": "Grassland green (#7cb342 with #558b2f overlay)",
    "houses": {
      "unpowered": "Brown house with roof, windows, door",
      "powered": "Yellow/gold (#ffcc00) when puzzle solved",
      "selected": "Yellow outline highlight",
      "number_display": "Shows required connections on roof"
    },
    "cables": {
      "unpowered": "Gray (#666666) lines",
      "powered": "Yellow (#ffcc00) when puzzle solved",
      "double_cable": "Two parallel lines with offset"
    }
  },

  "technical_architecture": {
    "framework": "Phaser 3.70.0",
    "setup": "Vite dev server, ES6 modules",
    "canvas": "1024x768px, FIT scaling mode",
    "files": [
      "index.html - Entry point",
      "main.js - Phaser config",
      "GameScene.js - Main game logic, UI, state management",
      "PuzzleGenerator.js - Generates solvable puzzles using Kruskal's algorithm",
      "House.js - House sprite, interactions, visual states",
      "CableManager.js - Cable connections, crossing detection, rendering"
    ]
  },

  "puzzle_generation": {
    "algorithm": "Kruskal's minimum spanning tree for guaranteed connectivity",
    "validation": [
      "All nodes connected in one graph",
      "No cable crossings",
      "No cables through houses",
      "Each node connections ≤ max for difficulty",
      "Each node has at least 1 connection"
    ],
    "extra_edges": "10-30% additional bridges added after spanning tree for complexity",
    "fallback": "If 100 generation attempts fail, use simple 4-node square puzzle"
  },

  "state_tracking": {
    "per_difficulty": {
      "completed_count": "Track puzzles completed per difficulty",
      "total_time": "Cumulative time spent per difficulty"
    },
    "current_puzzle": {
      "timer": "Counts up from 00:00",
      "difficulty": "Locked once puzzle starts",
      "solved_state": "Disables RESTART button when solved"
    }
  },

  "interaction_flow": {
    "game_start": "Instructions → Difficulty selection → Generate puzzle → Start timer",
    "during_puzzle": "Click house → yellow highlight → click another house → toggle cable (0→1→2→0)",
    "puzzle_complete": "Auto-check on each cable change → cascade power-on animation → victory popup",
    "report_unsolvable": "Confirmation dialog → log puzzle JSON to console → skip to new puzzle without stat increment",
    "next_puzzle": "Generate new puzzle with same difficulty → reset timer"
  },

  "key_constraints": {
    "no_browser_storage": "localStorage/sessionStorage not supported, use only in-memory state",
    "no_external_images": "All graphics drawn with Phaser graphics primitives",
    "cable_rules": "Max 2 cables between any two houses, must be straight lines",
    "button_states": "RESTART disabled when solved, Report disabled when solved or before first puzzle"
  }
}

